#include <iostream>
#include <deque>
using namespace std;
class Solution {
public: void add_front(int x) { deque.push_front(x); }
 void add_rear(int x) { deque.push_back(x); }
private: deque<int> deque;
};
int main() {
	int n, m;
	cin >> n >> m;
	Solution s;
	int x;
	for (int i = 0; i < n; i++) {
		cin >> x;
		s.add_front(x);
	}
	for (int i = 0; i < m; i++) {
		cin >> x;
		s.add_rear(x);
	}
	while (!deque.empty()) {
		cout << deque.front() << " ";
		deque.pop_front();
	}
	return 0;
}
